INSERT INTO topics (id, name, industry_ids, heat_score, heat_trend, start_date, expected_duration_days, expected_end_date, status, stage, catalysts, supply_chain, ai_summary, investment_strategy, avoid_list, risk_factors, meta) VALUES
  ('ccl_price_increase_2026', 'CCL 漲價循環', '["semiconductor_materials", "electronic_components"]'::jsonb, 95, 'rising', '2026-04-01', 180, '2026-10-01', 'active', 'main_rally', '[{"date": "2026-04-22", "event": "信越宣布 silicone 全線漲價 10%", "importance": 9}, {"date": "2026-04-20", "event": "外資調升台光電、台燿、臻鼎、金像電、聯茂目標價", "importance": 8}, {"date": "2026-04-17", "event": "建滔化工再調漲板料及 PP 價格 10%", "importance": 7}, {"date": "2026-04-01", "event": "Resonac、MGC 啟動第二波漲價", "importance": 8}]'::jsonb, '{"tier_1_raw_materials": {"name": "上游原料", "stocks": ["1815", "8358"], "status": "補漲"}, "tier_2_ccl": {"name": "中游 CCL", "stocks": ["2383", "6274", "6213"], "status": "已漲"}, "tier_3_resin": {"name": "上游樹脂材料", "stocks": ["4722", "4764", "3388"], "status": "主升段"}, "tier_4_pcb": {"name": "下游 PCB", "stocks": ["2368", "4958", "3044"], "status": "已漲"}}'::jsonb, '本波 CCL 漲價由 AI 伺服器需求爆發推動，日系信越帶頭漲價 10%，台廠台光電、台燿跟進調漲 20-40%，上游樹脂材料國精化、雙鍵成為真正受惠者。預期 2026 下半年還有第二波漲價。', '{"short_term_1w": ["1815", "8358"], "medium_term_1m": ["4722", "4764"], "long_term_6m": ["2383", "6274"]}'::jsonb, '[{"ticker": "1721", "reason": "連漲過多，注意股風險"}, {"ticker": "1711", "reason": "已漲超過 100%，短線乖離過大"}]'::jsonb, '["若台積電技術論壇後資金轉向 CoPoS 封裝，CCL 可能階段性退熱", "外資若隔日轉賣，短線有下殺 5-10% 風險"]'::jsonb, '{}'::jsonb),
  ('copos_advanced_packaging', 'CoPoS 先進封裝', '["semiconductor", "packaging_testing"]'::jsonb, 82, 'rising', '2026-04-01', 365, NULL, 'active', 'starting', '[{"date": "2026-04-22", "event": "台積電技術論壇 Santa Clara 站登場，首提 CoPoS", "importance": 10}, {"date": "2026-04-16", "event": "魏哲家法說會首度親口說出 CoPoS", "importance": 9}, {"date": "2026-01-15", "event": "CES 2026 台積電 CoPoS 實驗線啟動", "importance": 8}]'::jsonb, '{"tier_1_abf_substrate": {"name": "ABF 載板", "stocks": ["3037", "8046"], "status": "補漲"}, "tier_2_equipment": {"name": "先進封裝設備", "stocks": ["3680", "3583", "3131"], "status": "主升段"}, "tier_3_packaging": {"name": "封裝廠", "stocks": ["3711", "6239", "2449"], "status": "穩定"}, "tier_4_materials": {"name": "先進封裝材料", "stocks": ["4763", "3388"], "status": "早期"}}'::jsonb, '台積電首度正式揭露 CoPoS（方形封裝）技術路線圖，為 AI 晶片面積極限問題的核心解決方案。預計 2028 年後開始量產，設備與載板廠最直接受惠。', '{"short_term_1w": ["3037"], "medium_term_1m": ["3680", "3131"], "long_term_6m": ["3583", "3037", "8046"]}'::jsonb, '[]'::jsonb, '["CoPoS 技術難度高，推進時程可能延後", "2028 年量產，短期效益有限"]'::jsonb, '{}'::jsonb),
  ('silicon_photonics_cpo', '矽光子 CPO', '["semiconductor", "electronic_components"]'::jsonb, 76, 'rising', '2026-03-01', 365, NULL, 'active', 'main_rally', '[{"date": "2026-04-16", "event": "日月光宣告 2026 年為 CPO 商業化量產元年", "importance": 10}, {"date": "2026-04-10", "event": "NVIDIA 入股 Marvell，補齊 CPO 拼圖", "importance": 9}]'::jsonb, '{"tier_1_materials": {"name": "InP 磷化銦材料", "stocks": ["3081", "2455"], "status": "主升段"}, "tier_2_optical_modules": {"name": "光模組", "stocks": ["4979", "3163"], "status": "補漲"}, "tier_3_packaging": {"name": "CPO 封裝", "stocks": ["3711"], "status": "穩定"}}'::jsonb, '800G / 1.6T 超高速傳輸需求推動矽光子商用化。傳統銅線已達物理極限，CPO 成為 AI 資料中心必然方向。台股聯亞、華星光、波若威直接受惠。', '{"short_term_1w": ["4979"], "medium_term_1m": ["3081", "3163"], "long_term_6m": ["3711"]}'::jsonb, '[]'::jsonb, '["技術標準未完全統一", "量產時程不確定"]'::jsonb, '{}'::jsonb),
